#include <bits/stdc++.h>
using namespace std;

const int N=1e6+6,mod=1e9+7;

int n,h[N],mi[N];
char s[N];

int Hash(int l,int r){
    return (h[r]+mod-1LL*h[l-1]*mi[r-l+1]%mod)%mod;
}

int main(){
    scanf("%d%s",&n,s+1);
    mi[0]=1;
    for(int i=1;i<=n;i++)
        h[i]=(1LL*h[i-1]*31+s[i]-'a')%mod,mi[i]=1LL*mi[i-1]*31%mod;
    for(int i=1;i<=n;i++){
        bool flag=true;
        for(int j=2;i*j<=n;j++)
            if(Hash((j-1)*i+1,i*j)!=h[i]){
                flag=false;
                break;
            }
        if(flag && (n%i==0 || Hash(1,n%i)==Hash(n-n%i+1,n))){
            printf("%d",i);
            break;
        }
    }
    return 0;
}
